mapper.select:
SELECT * FROM ( SELECT main_q.*, ROWNUM AS rn FROM ( /* 1. 업무 히스토리 최신 20건 */ SELECT * FROM ( SELECT th.history_id AS historyId, th.task_id AS taskId, t.project_id AS projectId, th.action_type AS actionType, th.action_at AS actionAt, th.changed_by AS changedBy, /* 조인이 필요한 텍스트 정보는 안쪽에서 최소한으로 처리하거나 바깥에서 처리 */ p.project_title AS projectTitle, u.user_name AS userName, NVL(d_title.new_value, t.task_title) AS taskTitle, NVL(d_type.new_value, tt.type_name) AS typeName, cc.default_describe AS defaultDescribe FROM task_history th INNER JOIN task t ON th.task_id = t.task_id INNER JOIN users u ON th.changed_by = u.user_code INNER JOIN task_types tt ON t.type_id = tt.type_id LEFT JOIN project p ON t.project_id = p.project_id LEFT JOIN task_history_detail d_title ON th.history_id = d_title.history_id AND d_title.field_name = 'task_title' LEFT JOIN task_history_detail d_type ON th.history_id = d_type.history_id AND d_type.field_name = 'type_name' LEFT JOIN common_code cc ON t.task_status = cc.common_id AND cc.common_code = '0E'
AND t.project_id = #{projectId}
AND t.project_id IN
#{id}
ORDER BY th.action_at DESC ) WHERE ROWNUM <= 20
UNION ALL
/* 2. 위키 생성 최신 20건 */ SELECT * FROM ( SELECT NULL AS historyId, w.wiki_page_id AS taskId, w.project_id AS projectId, 'CREATE' AS actionType, w.created_at AS actionAt, w.user_code AS changedBy, p2.project_title AS projectTitle, u2.user_name AS userName, w.title AS taskTitle, '위키' AS typeName, '위키 생성' AS defaultDescribe FROM wiki_pages w INNER JOIN users u2 ON w.user_code = u2.user_code LEFT JOIN project p2 ON w.project_id = p2.project_id
AND w.project_id = #{projectId}
AND w.project_id IN
#{id}
ORDER BY w.created_at DESC ) WHERE ROWNUM <= 20
UNION ALL
/* 3. 위키 수정 최신 20건 */ SELECT * FROM ( SELECT NULL AS historyId, wp.wiki_page_id AS taskId, wp.project_id AS projectId, 'UPDATE' AS actionType, h.created_at AS actionAt, h.user_code AS changedBy, p3.project_title AS projectTitle, u3.user_name AS userName, h.title AS taskTitle, '위키' AS typeName, '위키 수정' AS defaultDescribe FROM wiki_histories h INNER JOIN wiki_pages wp ON h.wiki_page_id = wp.wiki_page_id INNER JOIN users u3 ON h.user_code = u3.user_code LEFT JOIN project p3 ON wp.project_id = p3.project_id
AND wp.project_id = #{projectId}
AND wp.project_id IN
#{id}
ORDER BY h.created_at DESC ) WHERE ROWNUM <= 20
) main_q ORDER BY actionAt DESC ) WHERE ROWNUM <= 20
